def _dbt_model_to_nested(dbt_model: DbtModel) -> DbtModelNested:
    """Convert flat DbtModel to nested format."""
    attrs = DbtModelAttributes()
    _populate_dbt_model_attrs(attrs, dbt_model)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dbt_model, _DBT_MODEL_REL_FIELDS, DbtModelRelationshipAttributes
    )
    return DbtModelNested(
        guid=dbt_model.guid,
        type_name=dbt_model.type_name,
        status=dbt_model.status,
        version=dbt_model.version,
        create_time=dbt_model.create_time,
        update_time=dbt_model.update_time,
        created_by=dbt_model.created_by,
        updated_by=dbt_model.updated_by,
        classifications=dbt_model.classifications,
        classification_names=dbt_model.classification_names,
        meanings=dbt_model.meanings,
        labels=dbt_model.labels,
        business_attributes=dbt_model.business_attributes,
        custom_attributes=dbt_model.custom_attributes,
        pending_tasks=dbt_model.pending_tasks,
        proxy=dbt_model.proxy,
        is_incomplete=dbt_model.is_incomplete,
        provenance_type=dbt_model.provenance_type,
        home_id=dbt_model.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dbt_model_from_nested(nested: DbtModelNested) -> DbtModel:
    """Convert nested format to flat DbtModel."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else DbtModelAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DBT_MODEL_REL_FIELDS,
        DbtModelRelationshipAttributes,
    )
    return DbtModel(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_dbt_model_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dbt_model_to_nested_bytes(dbt_model: DbtModel, serde: Serde) -> bytes:
    """Convert flat DbtModel to nested JSON bytes."""
    return serde.encode(_dbt_model_to_nested(dbt_model))


def _dbt_model_from_nested_bytes(data: bytes, serde: Serde) -> DbtModel:
    """Convert nested JSON bytes to flat DbtModel."""
    nested = serde.decode(data, DbtModelNested)
    return _dbt_model_from_nested(nested)


